jsLib:
function postUrl(url,method,params){
	return `${url},{
  "body": "requestData=${encodeURIComponent(JSON.stringify({Method: method,Parameters: params}))}",
  "method": "POST"
}`
}
function getUrl(url,method,params){
	return `${url}?requestData=${encodeURIComponent(JSON.stringify({Method: method,Parameters: params}))}`
}

